package main

import "fmt"

type Config struct {
	Debug   bool
	Timeout int
}

func enableDebugCopy(c Config) {
	c.Debug = true
}

func enableDebugPointer(c *Config) {
	c.Debug = true
}

func main() {
	c1 := Config{Debug: false, Timeout: 30}
	enableDebugCopy(c1)
	fmt.Println("After copy:", c1.Debug)

	c2 := Config{Debug: false, Timeout: 30}
	enableDebugPointer(&c2)
	fmt.Println("After pointer:", c2.Debug)
}

